sql:
SELECT alert_id, description 
FROM alerts 
WHERE tweet_id = (SELECT tweet_id FROM tweets WHERE text = 'myTweet');

SELECT COUNT(DISTINCT t.tweet_id) AS Total_Tweets
FROM tweets t
INNER JOIN tweet_hashtags th ON t.tweet_id = th.tweet_id;

SELECT tweet_type, COUNT(DISTINCT username) AS total_users
FROM tweets
GROUP BY tweet_type;

SELECT DISTINCT u.name, u.username
FROM users u
INNER JOIN tweets t ON u.username = t.username;

SELECT username, url, sentiment
FROM tweets
WHERE sentiment = 'positive' OR sentiment = 'neutral';

SELECT alert_id, COUNT(client_id) AS client_count
FROM client_alerts
GROUP BY alert_id;
